@page "/category/{CategorySlug}"

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName</h1>
<p>@CategoryDescription</p>

<div class="list-group">
    @foreach (var recipe in Recipes)
    {
        <a href="recipe/@recipe.Slug" class="list-group-item list-group-item-action">
            <div class="d-flex w-100 justify-content-between">
                <h5 class="mb-1">@recipe.Title</h5>
            </div>
            <p class="mb-1">@recipe.Summary</p>
        </a>
    }
</div>

@code {
    [Parameter]
    public string CategorySlug { get; set; } = "";

    private string CategoryName => CategorySlug switch
    {
        "appetizers" => "Appetizers",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        _ => "Recipes"
    };

    private string CategoryDescription => CategorySlug switch
    {
        "appetizers" => "Starters and small bites to kick off your meal.",
        "main-courses" => "Hearty entrées for lunch and dinner.",
        "desserts" => "Sweet treats to finish your meal.",
        _ => ""
    };

    private List<RecipeSummary> Recipes => CategorySlug switch
    {
        "appetizers" => new()
        {
            new("Bruschetta", "bruschetta", "Classic Italian toasted bread with tomatoes and basil."),
            new("Spinach Dip", "spinach-dip", "Creamy spinach and artichoke dip served warm."),
        },
        "main-courses" => new()
        {
            new("Spaghetti Carbonara", "spaghetti-carbonara", "Traditional Roman pasta with eggs, cheese, and pancetta."),
            new("Grilled Salmon", "grilled-salmon", "Fresh salmon fillet with lemon herb butter."),
        },
        "desserts" => new()
        {
            new("Chocolate Lava Cake", "chocolate-lava-cake", "Rich chocolate cake with a molten center."),
            new("Tiramisu", "tiramisu", "Classic Italian coffee-flavored layered dessert."),
        },
        _ => new()
    };

    private record RecipeSummary(string Title, string Slug, string Summary);
}

@page "/recipe/{RecipeSlug}"

<PageTitle>@GetRecipe().Title - RecipeShare</PageTitle>

@{ var recipe = GetRecipe(); }

<h1>@recipe.Title</h1>
<p class="text-muted">@recipe.Category</p>

<StarRating @rendermode="InteractiveServer" />

<h3>Ingredients</h3>
<ul>
    @foreach (var ingredient in recipe.Ingredients)
    {
        <li>@ingredient</li>
    }
</ul>

<h3>Steps</h3>
<ol>
    @foreach (var step in recipe.Steps)
    {
        <li class="mb-2">@step</li>
    }
</ol>

@code {
    [Parameter]
    public string RecipeSlug { get; set; } = "";

    private RecipeDetail GetRecipe() => RecipeSlug switch
    {
        "bruschetta" => new("Bruschetta", "Appetizers",
            new[] { "1 baguette, sliced", "4 tomatoes, diced", "Fresh basil", "2 cloves garlic", "Olive oil", "Salt and pepper" },
            new[] { "Preheat oven to 400°F (200°C).", "Brush bread slices with olive oil and toast until golden.", "Mix diced tomatoes, minced garlic, chopped basil, olive oil, salt, and pepper.", "Spoon tomato mixture onto toasted bread and serve immediately." }),
        "spinach-dip" => new("Spinach Dip", "Appetizers",
            new[] { "10 oz frozen spinach, thawed", "1 can artichoke hearts", "8 oz cream cheese", "1/2 cup sour cream", "1 cup parmesan cheese", "2 cloves garlic" },
            new[] { "Preheat oven to 350°F (175°C).", "Squeeze excess water from spinach.", "Mix all ingredients in a bowl.", "Transfer to a baking dish and bake 25 minutes until bubbly.", "Serve with crackers or bread." }),
        "spaghetti-carbonara" => new("Spaghetti Carbonara", "Main Courses",
            new[] { "400g spaghetti", "200g pancetta or guanciale", "4 egg yolks", "1 cup pecorino romano, grated", "Black pepper", "Salt" },
            new[] { "Cook spaghetti in salted boiling water until al dente.", "Crisp pancetta in a large pan over medium heat.", "Whisk egg yolks with grated cheese and black pepper.", "Drain pasta, reserving 1 cup pasta water.", "Toss hot pasta with pancetta, then remove from heat and stir in egg mixture.", "Add pasta water as needed for a creamy sauce. Serve immediately." }),
        "grilled-salmon" => new("Grilled Salmon", "Main Courses",
            new[] { "4 salmon fillets", "2 tbsp olive oil", "2 lemons", "Fresh dill", "4 tbsp butter", "Salt and pepper" },
            new[] { "Season salmon with salt, pepper, and olive oil.", "Preheat grill to medium-high heat.", "Grill salmon skin-side down for 4-5 minutes.", "Flip and cook another 3-4 minutes until done.", "Melt butter with lemon juice and dill.", "Drizzle herb butter over salmon and serve." }),
        "chocolate-lava-cake" => new("Chocolate Lava Cake", "Desserts",
            new[] { "6 oz dark chocolate", "1/2 cup butter", "2 eggs", "2 egg yolks", "1/4 cup sugar", "2 tbsp flour" },
            new[] { "Preheat oven to 425°F (220°C). Butter and flour ramekins.", "Melt chocolate and butter together.", "Whisk eggs, yolks, and sugar until thick.", "Fold chocolate mixture into eggs, then fold in flour.", "Divide batter among ramekins.", "Bake 12-14 minutes until edges are firm but center is soft.", "Invert onto plates and serve immediately." }),
        "tiramisu" => new("Tiramisu", "Desserts",
            new[] { "6 egg yolks", "3/4 cup sugar", "500g mascarpone", "2 cups heavy cream", "2 cups strong espresso, cooled", "3 tbsp coffee liqueur", "Ladyfinger biscuits", "Cocoa powder" },
            new[] { "Whisk egg yolks and sugar until thick and pale.", "Add mascarpone and mix until smooth.", "Whip heavy cream to stiff peaks and fold into mascarpone mixture.", "Combine espresso and coffee liqueur in a shallow dish.", "Briefly dip ladyfingers in coffee mixture and layer in a dish.", "Spread half the mascarpone cream over ladyfingers.", "Repeat layers, ending with cream.", "Refrigerate at least 4 hours. Dust with cocoa before serving." }),
        _ => new("Recipe Not Found", "",
            Array.Empty<string>(),
            new[] { "Sorry, this recipe could not be found." })
    };

    private record RecipeDetail(string Title, string Category, string[] Ingredients, string[] Steps);
}

@rendermode InteractiveServer

<div class="star-rating my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= CurrentRating ? "filled" : "")"
              @onclick="() => SetRating(star)"
              style="cursor: pointer; font-size: 1.5rem;">
            @(star <= CurrentRating ? "★" : "☆")
        </span>
    }
    @if (CurrentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @CurrentRating/5</span>
    }
</div>

@code {
    private int CurrentRating { get; set; }

    private void SetRating(int rating)
    {
        CurrentRating = rating;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been submitted for review.</p>
        <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Model.Ingredients" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Preparation Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps" />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }

    private void Reset()
    {
        Model = new();
        IsSubmitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the preparation steps.")]
        public string Steps { get; set; } = "";
    }
}

